mapper.delete:
DELETE FROM ai_stu_portrait_ability
WHERE stu_id = #{stuId}
    AND classroom_id = #{classroomId}
    AND course_id = #{courseId}

mapper.select:
SELECT ability_id as id,
       ability_name as abilityName,
       datavalue as dataValue,
       stu_datavalue as stuDataValue,
       import_level as importLevel
FROM ai_stu_portrait_ability
WHERE stu_id = #{stuId}
    AND classroom_id = #{classroomId}
    AND course_id = #{courseId}
    AND num = #{num}
